def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        penalty = 1.0
        bonus = 0.0
        decay = 1.0
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 == 0:
                penalty *= 1.05
            elif j % 2 == 0:
                penalty *= 0.95
            else:
                penalty *= 1.01
            if ratio < 0.1 * j:
                component = (np.cos(j) + j ** 1.3) * np.exp(-ratio * j) * penalty
            else:
                component = (np.log1p(j**2) + ratio**1.8) * penalty / (j + 2)
            if cap % (j+2) == 0:
                component *= 1.04
            elif (cap + j) % 5 == 0:
                component *= 0.96
            score += component
            if j % 7 == 0:
                for k in range(1, 7):
                    diff = cap - item * k
                    if diff == 0:
                        bonus += np.sqrt(abs(diff) + 1) * 2
                    elif diff > 0:
                        bonus += (np.sin(diff) + np.log1p(diff)) / (k + 2)
                        if diff % 3 == 0:
                            bonus *= 1.02
                    else:
                        bonus -= (abs(diff) ** 1.2) / (k + 3)
                        if abs(diff) % 4 == 1:
                            bonus *= 0.98
        decay = np.exp(-0.05 * ratio * cap)
        final_score = (score + bonus) * decay
        if final_score == 0:
            priorities[i] = np.inf
        elif final_score < 0:
            if cap > 10:
                priorities[i] = -final_score * np.log1p(cap**1.1 + item)
            else:
                priorities[i] = -final_score * np.sqrt(cap + item)
        else:
            if cap > item * 3:
                priorities[i] = -final_score / (np.sqrt(cap) + 0.5)
            else:
                priorities[i] = -final_score / (cap + 1.5)
        if ratio > 0.85:
            priorities[i] *= 1.25
            if cap % 2 == 0:
                priorities[i] *= 1.1
        elif ratio < 0.05:
            priorities[i] *= 0.75
            if cap % 5 == 0:
                priorities[i] *= 0.9
        if cap % 4 == 0 and (cap + item) % 7 == 0:
            priorities[i] *= 1.15
        elif (cap - item) % 6 == 0:
            priorities[i] *= 0.85
    return priorities
